import { useState } from "react";

function DynamicTableQuestion({
  columns,
  value,
  onChange
}) {

  const [rows, setRows] =
    useState(
      value || [{}]
    );

  const handleChange = (
    rowIndex,
    key,
    val
  ) => {

    const updatedRows =
      [...rows];

    updatedRows[rowIndex][key] =
      val;

    setRows(updatedRows);

    onChange(updatedRows);

  };

  const addRow = () => {

    const updatedRows = [
      ...rows,
      {}
    ];

    setRows(updatedRows);

    onChange(updatedRows);

  };

  return (

    <div>

      <table
        style={{
          width:"100%",
          borderCollapse:"collapse"
        }}
      >

        <thead>

          <tr>

            {
              columns.map(
                col => (

                  <th
                    key={col.key}
                    style={{
                      border:"1px solid #ddd",
                      padding:"10px"
                    }}
                  >
                    {col.label}
                  </th>

                )
              )
            }

          </tr>

        </thead>

        <tbody>

          {
            rows.map(
              (row,rowIndex)=>(

                <tr key={rowIndex}>

                  {
                    columns.map(
                      col => (

                        <td
                          key={col.key}
                          style={{
                            border:"1px solid #ddd",
                            padding:"5px"
                          }}
                        >

                          <input
                            type={
                              col.type === "date"
                                ? "date"
                                : col.type === "number"
                                ? "number"
                                : "text"
                            }
                            value={
                              row[col.key] || ""
                            }
                            onChange={(e)=>
                              handleChange(
                                rowIndex,
                                col.key,
                                e.target.value
                              )
                            }
                            style={{
                              width:"100%"
                            }}
                          />

                        </td>

                      )
                    )
                  }

                </tr>

              )
            )
          }

        </tbody>

      </table>

      <button
        onClick={addRow}
        type="button"
        style={{
          marginTop:"10px"
        }}
      >
        + Add Row
      </button>

    </div>

  );

}

export default DynamicTableQuestion;
